def deblur_system_call(params, input_fp, num_threads=None):
    logger = logging.getLogger(__name__)
    logger.debug('[%s] deblur system call params %s, input_fp %s, num_threads %s' % (mp.current_process().name, params, input_fp, num_threads))
    command = ['deblur', 'workflow', '--seqs-fp', input_fp, '--is-worker-thread', '--keep-tmp-files']
    command.extend(params)
    if num_threads is not None:
        command.extend(['--num-threads', str(num_threads)])
    logger.debug('[%s] running command %s' % (mp.current_process().name, command))
    return _system_call(command)
